Here is the commit message:
Reject excessively large primes in DH key generation.

CVE-2018-0732

Signed-off-by: Guido Vranken <guidovranken@gmail.com>

(cherry picked from commit 91f7361f47b082ae61ffe1a7b17bb2adf213c7fe)

Reviewed-by: Tim Hudson <tjh@openssl.org>
Reviewed-by: Matt Caswell <matt@openssl.org>
(Merged from https://github.com/openssl/openssl/pull/6457)

Here is the root cause:
The bug arises from the lack of validation for the size of the prime number used in Diffie-Hellman key generation, which could allow excessively large primes that may lead to security vulnerabilities, such as prolonged computation times or potential attacks exploiting the size of the modulus.

Here is the patch:

 static int generate_key(DH *dh)
 {
     int ok = 0;
     int generate_new_key = 0;
     unsigned l;
-    BN_CTX *ctx;
+    BN_CTX *ctx = NULL;
     BN_MONT_CTX *mont = NULL;
     BIGNUM *pub_key = NULL, *priv_key = NULL;

+    if (BN_num_bits(dh->p) > OPENSSL_DH_MAX_MODULUS_BITS) {
+        DHerr(DH_F_GENERATE_KEY, DH_R_MODULUS_TOO_LARGE);
+        return 0;
+    }
+
     ctx = BN_CTX_new();
     if (ctx == NULL)
         goto err;

     if (dh->priv_key == NULL) {
         priv_key = BN_new();
         if (priv_key == NULL)
             goto err;
         generate_new_key = 1;
     } else
         priv_key = dh->priv_key;

     if (dh->pub_key == NULL) {
         pub_key = BN_new();
         if (pub_key == NULL)
             goto err;
     } else
         pub_key = dh->pub_key;

     if (dh->flags & DH_FLAG_CACHE_MONT_P) {
         mont = BN_MONT_CTX_set_locked(&dh->method_mont_p,
                                       CRYPTO_LOCK_DH, dh->p, ctx);
         if (!mont)
             goto err;
     }

     if (generate_new_key) {
         if (dh->q) {
             do {
                 if (!BN_rand_range(priv_key, dh->q))
                     goto err;
             }
             while (BN_is_zero(priv_key) || BN_is_one(priv_key));
         } else {
             /* secret exponent length */
             l = dh->length ? dh->length : BN_num_bits(dh->p) - 1;
             if (!BN_rand(priv_key, l, 0, 0))
                 goto err;
         }
     }

     {
         BIGNUM local_prk;
         BIGNUM *prk;

         if ((dh->flags & DH_FLAG_NO_EXP_CONSTTIME) == 0) {
             BN_init(&local_prk);
             prk = &local_prk;
             BN_with_flags(prk, priv_key, BN_FLG_CONSTTIME);
         } else
             prk = priv_key;

         if (!dh->meth->bn_mod_exp(dh, pub_key, dh->g, prk, dh->p, ctx, mont))
             goto err;
     }

     dh->pub_key = pub_key;
     dh->priv_key = priv_key;
     ok = 1;
  err:
     if (ok != 1)
         DHerr(DH_F_GENERATE_KEY, ERR_R_BN_LIB);

     if ((pub_key != NULL) && (dh->pub_key == NULL))
         BN_free(pub_key);
     if ((priv_key != NULL) && (dh->priv_key == NULL))
         BN_free(priv_key);
     BN_CTX_free(ctx);
     return (ok);
 }



